  // Providers should be at main Index level, these are here just for the story example
  return (
    <Container>
      <NotificationProvider>
        <ModalProvider>
          <ModalAndNotification />
        </ModalProvider>
      </NotificationProvider>
    </Container>
  );
};

export default MixAlertsStory;

