      panelMetaData: {
        deviceIcon,
        leftSubTitle,
        leftTitle,
        rightTitle,
        rightSubTitle,
        hideIcon,
      },
      customBottom: showCustomComponent ? customBottom : undefined,
    }),
    [
      isEmptyWithIcon,
      noticeTitle,
      noticeMessage,
      status,
      noticeIcon,
      hasNotice,
      emptyIcon,
      deviceIcon,
      leftSubTitle,
      leftTitle,
      rightTitle,
      rightSubTitle,
      hideIcon,
      showCustomComponent,
    ]
  );

  const panelConfig: ICameraPanel[] = useMemo(
    () => [
      ImagePanel,
      VideoPanel,
      ImagePanel,
      VideoPanel,
      ImagePanel,
      VideoPanel,
      ImagePanel,
      VideoPanel,
      ImagePanel,
      VideoPanel,
      ImagePanel,
    ],
    [ImagePanel, VideoPanel]
  );

  return (
    <Container $showCustomComponent={showCustomComponent}>
      <CameraPanels panels={panelConfig} />
    </Container>
  );
};

